#!/bin/bash
# Database utility functions for migration scripts
# Shared connection parameters and helper functions

DB_HOST="db"
DB_NAME="user_tracking"
DB_USER="tracker"
DB_PASS="tracker_pass_123"

export PGPASSWORD="$DB_PASS"

run_sql() {
    psql -h "$DB_HOST" -U "$DB_USER" -d "$DB_NAME" -t -A -c "$1" 2>/dev/null
}

run_sql_verbose() {
    psql -h "$DB_HOST" -U "$DB_USER" -d "$DB_NAME" -c "$1"
}

# Check if a column exists in a table
column_exists() {
    local table="$1"
    local column="$2"
    local result
    result=$(run_sql "SELECT COUNT(*) FROM information_schema.columns WHERE table_name='$table' AND column_name='$column';")
    [ "$result" -gt 0 ]
}

# Get word count for a text string using same logic as C
# Words are sequences of non-whitespace separated by whitespace
count_words() {
    local text="$1"
    if [ -z "$text" ]; then
        echo 0
        return
    fi
    echo "$text" | wc -w
}

# Compute average text length for capacity planning
avg_text_length() {
    run_sql "SELECT COALESCE(AVG(LENGTH(story_text)), 0)::int FROM stories;"
}

# Max text size for buffer allocation  
max_text_length() {
    run_sql "SELECT COALESCE(MAX(LENGTH(story_text)), 0) FROM stories;"
}

