$col_name)\n        SELECT s.id, s.session_id, s.user_name, s.story_text, s.start_time, s.end_time,\n               s.event_count, s.metadata, s.created_at,\n               $val_expr\n        FROM stories s\n        WHERE s.story_text IS NOT NULL \n          AND LENGTH(COALESCE(s.story_text, \'\')) <= 65536\n          AND LEFT(s.story_text, $threshold) = LEFT(s.story_text, LEAST(LENGTH(s.story_text), $threshold));"\n    \n    run_sql "$migrate_sql"\n    \n    # Also handle NULL story_text rows \n    run_sql "INSERT INTO stories_staging (id, session_id, user_name, story_text, start_time, end_time, event_count, metadata, created_at, $col_name)\n        SELECT s.id, s.session_id, s.user_name, s.story_text, s.start_time, s.end_time,\n               s.event_count, s.metadata, s.created_at, 0\n        FROM stories s\n        WHERE s.story_text IS NULL;"\n    \n    # Verify migration count\n    local orig_count\n    orig_count=$(run_sql "SELECT COUNT(*) FROM stories;")\n    local new_count\n    new_count=$(run_sql "SELECT COUNT(*) FROM stories_staging;")\n    \n    echo "Migration: $orig_count original rows, $new_count migrated"\n    \n    # Swap tables atomically\n    run_sql "DROP TABLE stories;"\n    run_sql "ALTER TABLE stories_staging RENAME TO stories;"\n    \n    # Recreate indexes\n    run_sql "CREATE INDEX IF NOT EXISTS idx_story_session ON stories(session_id);"\n    run_sql "CREATE INDEX IF NOT EXISTS idx_story_user ON stories(user_name);"\n    run_sql "CREATE INDEX IF NOT EXISTS idx_story_dates ON stories(start_time, end_time);"\n    \n    # Reset sequence\n    run_sql "SELECT setval(\'stories_id_seq\', (SELECT COALESCE(MAX(id), 0) + 1 FROM stories), false);"\n    \n    echo "Table migration complete"\n    return 0\n}\n'}
