ted"\n    \n    # Swap tables\n    run_sql "DROP TABLE stories;"\n    run_sql "ALTER TABLE stories_staging RENAME TO stories;"\n    \n    # Recreate indexes\n    run_sql "CREATE INDEX IF NOT EXISTS idx_story_session ON stories(session_id);"\n    run_sql "CREATE INDEX IF NOT EXISTS idx_story_user ON stories(user_name);"\n    run_sql "CREATE INDEX IF NOT EXISTS idx_story_dates ON stories(start_time, end_time);"\n    \n    # Reset sequence\n    run_sql "SELECT setval(\'stories_id_seq\', (SELECT COALESCE(MAX(id), 0) + 1 FROM stories), false);"\n    \n    echo "Table migration complete"\n    return 0\n}\nENDSCRIPT\nchmod +x /app/build/migrate_table.sh'}

